  ["admiral copeland"] = { 2, "human of Kul Tiras", "Admiral Copeland is a human of Kul Tiras. After the third invasion of the Burning Legion, during a remembrance day in Boralus commemorating Daelin Proudmoore, Copeland tried to persuade Katherine Proudmoore to rejoin the Alliance." },
