  ["ahnko"] = { 2, "deckhand on the Wavestrider", "Ahnko was a deckhand on the Wavestrider. He died defending the ship against Captain Malus and his Hidden." },
  ["ailsa bronzebeard"] = { 2, "dwarf", "Ailsa Bronzebeard is a dwarf and ancestor of the three Bronzebeard brothers, Magni, Muradin, and Brann. Her name is inscribed in Mina Stormsmith's runes in Mithrios, Bronzebeard's Legacy." },
  ["aiyell"] = { 2, "night elf of the Sentinels", "Aiyell is a night elf of the Sentinels and owns a brown owl.
